<?php
namespace Tests\Unit;
use App\Services\Trading\PositionManagementSelectionService;
use Tests\TestCase;
class PositionManagementSelectionServiceTest extends TestCase
{protected function candidate(array $over=[]):array{return array_replace_recursive(['schema_version'=>'trading_position_management_candidate_v1','status'=>'policy_hypothesis','candidate_id'=>str_repeat('a',64),'candidate_type'=>'protection_breach_review','position_id'=>'position-bumi-1','ticker'=>'BUMI','position_side'=>'long','condition'=>'stop_reference_breached','reason_codes'=>[]],$over);}protected function state():array{return ['schema_version'=>'trading_position_state_v1','status'=>'condition_observed','position_id'=>'position-bumi-1','ticker'=>'BUMI','position_side'=>'long'];}protected function eval():array{return ['schema_version'=>'trading_position_management_policy_evaluation_v1','status'=>'matched_reference_rule','state_condition'=>'stop_reference_breached'];}public function test_no_blocked_and_invalid_candidate():void{$svc=new PositionManagementSelectionService();$r=$svc->select(['decision_scope'=>'position_management','position_state'=>$this->state(),'policy_evaluation'=>$this->eval(),'management_candidate'=>null]);$this->assertSame('candidate_unavailable',$r['status']);$b=$svc->select(['decision_scope'=>'position_management','position_state'=>$this->state(),'policy_evaluation'=>$this->eval(),'management_candidate'=>$this->candidate(['status'=>'blocked'])]);$this->assertSame('candidate_unavailable',$b['status']);}
public function test_reference_candidate_not_selectable():void{$svc=new PositionManagementSelectionService();$r=$svc->select(['decision_scope'=>'position_management','position_state'=>$this->state(),'policy_evaluation'=>$this->eval(),'management_candidate'=>$this->candidate()]);$this->assertSame('candidate_reference_only',$r['status']);$this->assertSame('eligible_but_not_selectable',$r['selection_eligibility']);$this->assertNull($r['selected_management_action']);$this->assertNull($r['promoted_management_action']);$this->assertNull($r['executable_instruction']);$this->assertSame('WAIT',$r['safety_action']);$this->assertSame('unavailable',$r['management_risk']['status']);$this->assertSame('unavailable',$r['management_plan']['status']);$this->assertSame('unavailable',$r['portfolio_approval']['status']);}
public function test_gate_order_and_validation():void{$svc=new PositionManagementSelectionService();$r=$svc->select(['decision_scope'=>'position_management','position_state'=>$this->state(),'policy_evaluation'=>$this->eval(),'management_candidate'=>$this->candidate()]);$this->assertSame(['decision_scope','position_state_availability'],array_slice(array_column($r['selection_gates'],'gate'),0,2));$r['selected_management_action']='SELL';$this->expectException(\InvalidArgumentException::class);$svc->validateSelection($r);}}
